import React, { useState, useEffect, useCallback } from 'react';
import usePageTitle from '../hooks/usePageTitle';
import { api, apiPost } from '../utils/api';

/* ── Design tokens (matches MissionControlPage / SystemHealthPage) ───────── */
import { tokens } from '../styles/tokens';
import s from './OperatorEventsPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

/* ── Helpers ─────────────────────────────────────────────────────────────── */
function timeAgo(ts) {
  if (!ts) return 'never';
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
  const diff = Date.now() - ms;
  const secs = Math.floor(diff / 1000);
  if (secs < 0) return 'just now';
  if (secs < 60) return secs + 's ago';
  const mins = Math.floor(secs / 60);
  if (mins < 60) return mins + 'm ago';
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return hrs + 'h ago';
  return Math.floor(hrs / 24) + 'd ago';
}

function formatTs(ts) {
  if (!ts) return '--';
  try {
    const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
    return new Date(ms).toLocaleString('en-US', {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit',
    });
  } catch { return '--'; }
}

/* ── Severity Color ──────────────────────────────────────────────────────── */
function severityColor(sev) {
  if (!sev) return C.textSecondary;
  const sv = sev.toLowerCase();
  if (sv === 'info') return C.blue;
  if (sv === 'warning' || sv === 'warn') return C.amber;
  if (sv === 'critical' || sv === 'error') return C.red;
  return C.textSecondary;
}

/* ── Source badge color ──────────────────────────────────────────────────── */
function sourceColor(src) {
  if (!src) return C.textSecondary;
  const sv = src.toLowerCase();
  if (sv === 'github') return C.purple;
  if (sv === 'alertmanager') return C.red;
  if (sv === 'gateway') return C.cyan;
  if (sv === 'operator') return C.blue;
  if (sv === 'self-heal' || sv === 'self_heal') return C.green;
  return C.textSecondary;
}

/* ── Status color for intents ────────────────────────────────────────────── */
function intentStatusColor(status) {
  if (!status) return C.textSecondary;
  const sv = status.toLowerCase();
  if (sv === 'succeeded' || sv === 'approved' || sv === 'auto-executed' || sv === 'auto_executed') return C.green;
  if (sv === 'denied' || sv === 'rejected' || sv === 'failed') return C.red;
  if (sv === 'pending') return C.amber;
  return C.blue;
}

/* ── Tab Button ──────────────────────────────────────────────────────────── */
function TabButton({ label, active, onClick, badge }) {
  return (
    <button
      onClick={onClick}
      className={`${s.tabButton} ${active ? s.tabButtonActive : s.tabButtonInactive}`}
    >
      {label}
      {badge > 0 && <span className={s.tabBadge}>{badge}</span>}
    </button>
  );
}

/* ── Approval Confirmation Modal (with multi-approver fields) ──────────── */
function ApprovalModal({ intent, onClose, onApprove }) {
  const [confirmText, setConfirmText] = useState('');
  const [approverRole, setApproverRole] = useState('');
  const [providedInputs, setProvidedInputs] = useState([{ key: '', value: '' }]);
  const [providedArtifacts, setProvidedArtifacts] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const isTrading = intent?.runbook?.toLowerCase().includes('trading') ||
    intent?.runbook?.toLowerCase().includes('ibkr') ||
    intent?.runbook?.toLowerCase().includes('gateway') ||
    intent?.params?.involves_trading;
  const canApprove = confirmText === 'CONFIRM';

  const handleApprove = async () => {
    if (!canApprove) return;
    setSubmitting(true);
    const extra = {};
    if (approverRole.trim()) extra.role = approverRole.trim();
    const inputs = {};
    providedInputs.forEach(e => { if (e.key.trim()) inputs[e.key.trim()] = e.value; });
    if (Object.keys(inputs).length > 0) extra.provided_inputs = inputs;
    if (providedArtifacts.trim()) {
      extra.provided_artifacts = providedArtifacts.split('\n').map(sv => sv.trim()).filter(Boolean);
    }
    await onApprove(intent.id, extra);
    setSubmitting(false);
    onClose();
  };

  if (!intent) return null;

  const reqApprovers = intent.required_approvers;
  const reqRoles = intent.required_roles || [];
  const approvalsList = intent.approvals_list || [];
  const currentCount = approvalsList.length;
  const reqInputs = intent.required_inputs || [];
  const reqArtifacts = intent.required_artifacts || [];

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={e => e.stopPropagation()} className={s.modalApproval}>
        <h3 className={s.modalTitle}>Approve GUARDED Action</h3>

        {/* Trading DISARM banner */}
        {isTrading && (
          <div className={s.tradingBanner}>
            <div className={s.tradingBannerLabel}>TRADING DISARM</div>
            <div className={s.tradingBannerDesc}>
              This action involves trading infrastructure. Trading will be temporarily disarmed during execution.
            </div>
          </div>
        )}

        {/* Policy requirements banner */}
        {reqApprovers !== undefined && reqApprovers > 0 && (
          <div className={s.policyBanner}>
            <div className={s.policyBannerLabel}>POLICY REQUIREMENT</div>
            <div className={s.policyBannerDesc}>
              Requires {reqApprovers} approval{reqApprovers > 1 ? 's' : ''}
              {reqRoles.length > 0 && ` from roles: ${reqRoles.join(', ')}`}
            </div>
            {currentCount > 0 && (
              <div className={s.policyProgress}>{currentCount}/{reqApprovers} received</div>
            )}
          </div>
        )}

        {/* Intent details */}
        <div className={s.detailFields}>
          <div className={s.detailColumn}>
            <div>
              <span className={s.fieldLabel}>Runbook</span>
              <div className={s.fieldValue}>{intent.runbook || intent.runbook_name || '--'}</div>
            </div>
            <div>
              <span className={s.fieldLabel}>Triggered By</span>
              <div className={s.fieldValue}>{intent.triggered_by || intent.event_type || '--'}</div>
            </div>
            {intent.params && Object.keys(intent.params).length > 0 && (
              <div>
                <span className={s.fieldLabel}>Parameters</span>
                <pre className={s.paramsPre}>
                  {JSON.stringify(intent.params, null, 2)}
                </pre>
              </div>
            )}
          </div>
        </div>

        {/* Approver role */}
        {reqRoles.length > 0 && (
          <div className={s.formGroup}>
            <label className={s.formLabel}>Your Role</label>
            <select
              value={approverRole}
              onChange={e => setApproverRole(e.target.value)}
              className={s.formSelect}
            >
              <option value="">-- Select role --</option>
              {reqRoles.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
        )}

        {/* Provided inputs */}
        {reqInputs.length > 0 && (
          <div className={s.formGroup}>
            <label className={s.formLabel}>Required Inputs</label>
            <div className={s.inputColumn}>
              {providedInputs.map((entry, i) => (
                <div key={i} className={s.inputRow}>
                  <input
                    type="text"
                    value={entry.key}
                    onChange={e => {
                      const updated = [...providedInputs];
                      updated[i] = { ...updated[i], key: e.target.value };
                      setProvidedInputs(updated);
                    }}
                    placeholder="key"
                    className={s.formInputSmall}
                  />
                  <input
                    type="text"
                    value={entry.value}
                    onChange={e => {
                      const updated = [...providedInputs];
                      updated[i] = { ...updated[i], value: e.target.value };
                      setProvidedInputs(updated);
                    }}
                    placeholder="value"
                    className={s.formInputSmall}
                  />
                </div>
              ))}
              <button
                onClick={() => setProvidedInputs(prev => [...prev, { key: '', value: '' }])}
                className={s.addInputBtn}
              >
                + Add Input
              </button>
            </div>
          </div>
        )}

        {/* Provided artifacts */}
        {reqArtifacts.length > 0 && (
          <div className={s.formGroup}>
            <label className={s.formLabel}>Required Artifacts (one per line)</label>
            <textarea
              value={providedArtifacts}
              onChange={e => setProvidedArtifacts(e.target.value)}
              placeholder="artifact_url_or_path"
              rows={3}
              className={s.formTextarea}
            />
          </div>
        )}

        {/* Confirmation input */}
        <div style={{ marginBottom: 16 }}>
          <label className={s.formLabel}>
            Type <span className={s.confirmHighlight}>CONFIRM</span> to approve
          </label>
          <input
            type="text"
            value={confirmText}
            onChange={e => setConfirmText(e.target.value)}
            placeholder="CONFIRM"
            className={s.formInput}
            style={{ border: `1px solid ${canApprove ? C.green : C.border}` }}
          />
        </div>

        {/* Buttons */}
        <div className={s.modalActions}>
          <button onClick={onClose} className={s.btnCancel}>Cancel</button>
          <button
            onClick={handleApprove}
            disabled={!canApprove || submitting}
            className={`${s.btnApprove} ${canApprove && !submitting ? s.btnApproveEnabled : s.btnApproveDisabled}`}
          >
            {submitting ? 'Approving...' : 'Approve'}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ── Deny Modal ──────────────────────────────────────────────────────────── */
function DenyModal({ intent, onClose, onDeny }) {
  const [note, setNote] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const handleDeny = async () => {
    setSubmitting(true);
    await onDeny(intent.id, note);
    setSubmitting(false);
    onClose();
  };

  if (!intent) return null;

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={e => e.stopPropagation()} className={s.modalDeny}>
        <h3 className={s.modalTitle}>Deny Intent</h3>
        <div className={s.denyTarget}>
          Denying: <span className={s.denyTargetName}>{intent.runbook || intent.runbook_name || '--'}</span>
        </div>
        <div style={{ marginBottom: 16 }}>
          <label className={s.formLabel}>Note (optional)</label>
          <textarea
            value={note}
            onChange={e => setNote(e.target.value)}
            placeholder="Reason for denial..."
            rows={3}
            className={s.formTextarea}
          />
        </div>
        <div className={s.modalActions}>
          <button onClick={onClose} className={s.btnCancel}>Cancel</button>
          <button
            onClick={handleDeny}
            disabled={submitting}
            className={`${s.btnDenyAction} ${submitting ? s.btnDenyDisabled : ''}`}
          >
            {submitting ? 'Denying...' : 'Deny'}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   OPERATOR EVENTS PAGE
   ═══════════════════════════════════════════════════════════════════════════ */
export default function OperatorEventsPage() {
  usePageTitle('Operator Events');

  const [activeTab, setActiveTab] = useState('events');
  const [events, setEvents] = useState([]);
  const [intents, setIntents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Events filters
  const [sourceFilter, setSourceFilter] = useState('all');
  const [severityFilter, setSeverityFilter] = useState('all');

  // Intents sub-tab
  const [intentSubTab, setIntentSubTab] = useState('pending');

  // Expanded event
  const [expandedEventId, setExpandedEventId] = useState(null);

  // Modals
  const [approveIntent, setApproveIntent] = useState(null);
  const [denyIntent, setDenyIntent] = useState(null);

  const fetchAll = useCallback(async () => {
    try {
      const [eventsData, intentsData, healExecs, healthScore, controlHealth] = await Promise.all([
        api('/operator/events?limit=100').catch(() => null),
        api('/operator/intents?limit=100').catch(() => null),
        api('/self-heal/executions?limit=50').catch(() => null),
        api('/health/score').catch(() => null),
        api('/control/health').catch(() => null),
      ]);

      let allEvents = [];
      if (eventsData) {
        const list = Array.isArray(eventsData) ? eventsData : eventsData.events || [];
        allEvents = [...list];
      }

      if (healExecs) {
        const execs = Array.isArray(healExecs) ? healExecs : healExecs.executions || [];
        execs.forEach(ex => {
          allEvents.push({
            id: ex.id || `heal-${ex.triggered_at}`,
            timestamp: ex.triggered_at || ex.completed_at,
            type: 'self-heal',
            event_type: 'self-heal',
            source: 'self-heal',
            severity: ex.status === 'executed' ? 'info' : ex.status === 'pending_approval' ? 'warning' : 'info',
            service: ex.healer_name || ex.healer_id || 'Self-Heal',
            message: `${ex.action || 'action'} - ${ex.status || 'unknown'}${ex.classification ? ` (${ex.classification})` : ''}`,
            payload: ex,
          });
        });
      }

      if (healthScore && healthScore.components) {
        const ts = healthScore.last_check || new Date().toISOString();
        Object.entries(healthScore.components).forEach(([key, comp]) => {
          const score = comp.score ?? 100;
          let severity = 'info';
          if (score < 50) severity = 'critical';
          else if (score < 80) severity = 'warning';
          allEvents.push({
            id: `health-${key}-${ts}`,
            timestamp: ts,
            type: 'health-check',
            event_type: 'health-check',
            source: 'gateway',
            severity,
            service: key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()),
            message: `Score ${score}/100 - ${typeof comp.detail === 'string' ? comp.detail : JSON.stringify(comp.detail)}`,
            payload: { key, ...comp, overall_score: healthScore.score, overall_status: healthScore.status },
          });
        });
      }

      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      if (controlHealth && controlHealth.bots) {
        const bots = controlHealth.bots;
        Object.entries(bots).filter(([name]) => !PAPER_BOTS.has(name.toLowerCase())).forEach(([name, bot]) => {
          if (!bot || typeof bot !== 'object' || !bot.status) return;
          const payload = bot.payload || {};
          const trades = payload.trades || [];
          allEvents.push({
            id: `bot-status-${name}-${bot.ts || Date.now()}`,
            timestamp: bot.ts || payload.ts || new Date().toISOString(),
            type: 'bot-status',
            event_type: 'bot-status',
            source: 'operator',
            severity: bot.status === 'OK' ? 'info' : 'warning',
            service: name.toUpperCase(),
            message: `Bot ${name.toUpperCase()}: ${bot.status} | mode=${payload.mode || '--'} | positions=${(payload.positions || []).length}`,
            payload: { bot: name, status: bot.status, mode: payload.mode, equity: payload.equity },
          });
          trades.slice(0, 5).forEach(trade => {
            allEvents.push({
              id: `trade-${name}-${trade.order_id}-${trade.timestamp}`,
              timestamp: trade.timestamp,
              type: 'trade',
              event_type: 'trade',
              source: 'operator',
              severity: trade.status === 'Filled' ? 'info' : trade.status === 'ValidationError' ? 'warning' : 'info',
              service: `${name.toUpperCase()} / ${trade.venue || '--'}`,
              message: `${trade.action} ${trade.qty} ${trade.symbol} @ ${trade.fill_price || trade.limit_price || 'MKT'} - ${trade.status}`,
              payload: trade,
            });
          });
        });
      }

      allEvents.sort((a, b) => {
        const ta = typeof a.timestamp === 'number' ? a.timestamp : new Date(a.timestamp || 0).getTime() / 1000;
        const tb = typeof b.timestamp === 'number' ? b.timestamp : new Date(b.timestamp || 0).getTime() / 1000;
        return tb - ta;
      });

      setEvents(allEvents);

      if (intentsData) {
        const list = Array.isArray(intentsData) ? intentsData : intentsData.intents || [];
        setIntents(list);
      }
      setError(null);
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchAll();
    const iv = setInterval(fetchAll, 15000);
    return () => clearInterval(iv);
  }, [fetchAll]);

  const handleApprove = async (intentId, extra = {}) => {
    const payload = {
      confirm_phrase: 'CONFIRM',
      approved_by: 'admin',
      ...extra,
    };
    const result = await apiPost(`/operator/intents/${intentId}/approve`, payload);
    if (result) fetchAll();
  };

  const handleDeny = async (intentId, note) => {
    const result = await apiPost(`/operator/intents/${intentId}/deny`, {
      denied_by: 'admin',
      note: note || '',
    });
    if (result) fetchAll();
  };

  const filteredEvents = events.filter(ev => {
    if (sourceFilter !== 'all' && (ev.source || '').toLowerCase() !== sourceFilter) return false;
    if (severityFilter !== 'all' && (ev.severity || '').toLowerCase() !== severityFilter) return false;
    return true;
  });

  const pendingIntents = intents.filter(i => (i.status || '').toLowerCase() === 'pending');
  const historyIntents = intents.filter(i => (i.status || '').toLowerCase() !== 'pending');
  const pendingCount = pendingIntents.length;

  return (
    <div className={s.page}>

      {/* ── Header ──────────────────────────────────────────────────────── */}
      <div className={s.header}>
        <div>
          <h1 className={s.headerTitle}>Operator Events</h1>
          <p className={s.headerSubtitle}>
            Event stream, intent management, and approval workflow
          </p>
        </div>
        <div className={s.headerMeta}>
          <div className={s.headerMetaText}>
            {events.length} events | {pendingCount} pending
          </div>
        </div>
      </div>

      {error && (
        <div className={s.errorBanner}>
          Failed to load: {typeof error === 'string' ? error : 'An error occurred'}
        </div>
      )}

      {/* ── Tab Bar ─────────────────────────────────────────────────────── */}
      <div className={s.tabBar}>
        <TabButton label="Events" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
        <TabButton label="Intents" active={activeTab === 'intents'} onClick={() => setActiveTab('intents')} badge={pendingCount} />
      </div>

      {/* ════════════════════════════════════════════════════════════════════
         EVENTS TAB
         ════════════════════════════════════════════════════════════════════ */}
      {activeTab === 'events' && (
        <div className={s.panel}>
          <div className={`${s.sectionHeader} ${s.sectionHeaderRow}`}>
            <span>Event Stream</span>
            <div className={s.filterRow}>
              <select
                value={sourceFilter}
                onChange={e => setSourceFilter(e.target.value)}
                className={s.filterSelect}
              >
                <option value="all">All Sources</option>
                <option value="operator">Operator</option>
                <option value="self-heal">Self-Heal</option>
                <option value="gateway">Gateway</option>
                <option value="github">GitHub</option>
                <option value="alertmanager">AlertManager</option>
              </select>
              <select
                value={severityFilter}
                onChange={e => setSeverityFilter(e.target.value)}
                className={s.filterSelect}
              >
                <option value="all">All Severities</option>
                <option value="info">Info</option>
                <option value="warning">Warning</option>
                <option value="critical">Critical</option>
              </select>
              <span className={s.refreshLabel}>Auto-refresh 15s</span>
            </div>
          </div>

          {filteredEvents.length === 0 ? (
            <div className={s.emptyState}>
              {loading ? (
                <div className={s.emptyLoadingText}>Loading events...</div>
              ) : (
                <div>
                  <div className={s.emptyTitle}>
                    {sourceFilter !== 'all' || severityFilter !== 'all'
                      ? 'No events match your filters'
                      : 'No system events yet'}
                  </div>
                  <div className={s.emptyDesc}>
                    {sourceFilter !== 'all' || severityFilter !== 'all'
                      ? 'Try changing the source or severity filter to see more events.'
                      : 'Events from bot heartbeats, self-heal actions, and health checks will appear here as they occur. The page refreshes every 15 seconds.'}
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className={s.eventsList}>
              {filteredEvents.map((ev, i) => {
                const evId = ev.id || i;
                const isExpanded = expandedEventId === evId;
                const sevColor = severityColor(ev.severity);
                const srcColor = sourceColor(ev.source);

                return (
                  <div key={evId}>
                    <div
                      onClick={() => setExpandedEventId(isExpanded ? null : evId)}
                      className={`${s.eventRow} ${isExpanded ? s.eventRowExpanded : ''}`}
                      style={{ borderLeft: `3px solid ${sevColor}30` }}
                    >
                      <span className={s.eventTimestamp}>{formatTs(ev.timestamp)}</span>
                      <span
                        className={s.eventBadge}
                        style={{ color: srcColor, background: `${srcColor}12`, border: `1px solid ${srcColor}25` }}
                      >
                        {ev.type || ev.event_type || '--'}
                      </span>
                      <span
                        className={s.eventSourceBadge}
                        style={{ color: srcColor, background: `${srcColor}08` }}
                      >
                        {ev.source || '--'}
                      </span>
                      <span
                        className={s.severityBadge}
                        style={{ color: sevColor, background: `${sevColor}12`, border: `1px solid ${sevColor}25` }}
                      >
                        <span className={s.severityDot} style={{ background: sevColor }} />
                        {ev.severity || 'info'}
                      </span>
                      <span className={s.eventService}>{ev.service || '--'}</span>
                      <span className={s.eventMessage}>{ev.message || ev.summary || '--'}</span>
                    </div>

                    {/* Expanded payload */}
                    {isExpanded && (
                      <div className={s.expandedPayload} style={{ borderLeft: `3px solid ${sevColor}30` }}>
                        <div className={s.payloadLabel}>Full Payload</div>
                        <pre className={s.payloadPre}>
                          {JSON.stringify(ev.payload || ev, null, 2)}
                        </pre>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* ════════════════════════════════════════════════════════════════════
         INTENTS TAB
         ════════════════════════════════════════════════════════════════════ */}
      {activeTab === 'intents' && (
        <div>
          {/* Sub-tab bar */}
          <div className={s.subTabBar}>
            <TabButton label="Pending" active={intentSubTab === 'pending'} onClick={() => setIntentSubTab('pending')} badge={pendingCount} />
            <TabButton label="History" active={intentSubTab === 'history'} onClick={() => setIntentSubTab('history')} />
          </div>

          {/* ── Pending Intents ─────────────────────────────────────────── */}
          {intentSubTab === 'pending' && (
            <div>
              {pendingIntents.length === 0 ? (
                <div className={s.panel}>
                  <div className={s.pendingEmpty}>No pending intents. All clear.</div>
                </div>
              ) : (
                <div className={s.intentsGrid}>
                  {pendingIntents.map(intent => {
                    const classification = (intent.classification || 'GUARDED').toUpperCase();
                    const classColor = classification === 'AUTO' ? C.green : C.amber;
                    const reqApprovers = intent.required_approvers;
                    const reqRoles = intent.required_roles || [];
                    const approvalsList = intent.approvals_list || [];
                    const currentCount = approvalsList.length;
                    const denyConditions = intent.deny_conditions || [];
                    const reqInputs = intent.required_inputs || [];
                    const reqArtifacts = intent.required_artifacts || [];

                    return (
                      <div key={intent.id} className={s.intentCard} style={{ borderTop: `3px solid ${classColor}` }}>
                        {/* Header */}
                        <div className={s.intentCardHeader}>
                          <span className={s.intentName}>
                            {intent.runbook || intent.runbook_name || 'Unknown Runbook'}
                          </span>
                          <span
                            className={s.classBadge}
                            style={{ color: classColor, background: `${classColor}15`, border: `1px solid ${classColor}25` }}
                          >
                            {classification}
                          </span>
                        </div>

                        {/* Deny conditions */}
                        {denyConditions.length > 0 && denyConditions.map((cond, ci) => (
                          <div key={ci} className={s.denyCondition}>
                            {typeof cond === 'string' ? cond : cond.description || cond.condition || JSON.stringify(cond)}
                          </div>
                        ))}

                        {/* Policy requirements */}
                        {reqApprovers !== undefined && reqApprovers > 0 && (
                          <div className={s.policyReqBox}>
                            <div className={s.policyReqText}>
                              Requires {reqApprovers} approval{reqApprovers > 1 ? 's' : ''}
                              {reqRoles.length > 0 && (
                                <span> from {reqRoles.map((r, ri) => (
                                  <span key={ri} className={s.roleBadge}>{r}</span>
                                ))}</span>
                              )}
                            </div>
                            {/* Approvals progress */}
                            <div className={s.approvalProgress}>
                              <div className={s.approvalBar}>
                                <div
                                  className={s.approvalBarFill}
                                  style={{
                                    width: `${reqApprovers > 0 ? (currentCount / reqApprovers) * 100 : 0}%`,
                                    background: currentCount >= reqApprovers ? C.green : C.amber,
                                  }}
                                />
                              </div>
                              <span className={s.approvalCount}>{currentCount}/{reqApprovers}</span>
                            </div>
                            {/* Who approved */}
                            {approvalsList.length > 0 && (
                              <div className={s.approvalChips}>
                                {approvalsList.map((ap, ai) => (
                                  <span key={ai} className={s.approvalChip}>
                                    {typeof ap === 'string' ? ap : ap.approved_by || ap.name || `Approver ${ai + 1}`}
                                    {typeof ap === 'object' && ap.role ? ` (${ap.role})` : ''}
                                  </span>
                                ))}
                              </div>
                            )}
                          </div>
                        )}

                        {/* Required inputs/artifacts */}
                        {(reqInputs.length > 0 || reqArtifacts.length > 0) && (
                          <div className={s.reqBox}>
                            {reqInputs.length > 0 && (
                              <div style={{ marginBottom: reqArtifacts.length > 0 ? 6 : 0 }}>
                                <span className={s.reqLabel}>Required Inputs:</span>
                                <span className={s.reqInputValue}>
                                  {reqInputs.map(inp => typeof inp === 'string' ? inp : inp.name || JSON.stringify(inp)).join(', ')}
                                </span>
                              </div>
                            )}
                            {reqArtifacts.length > 0 && (
                              <div>
                                <span className={s.reqLabel}>Required Artifacts:</span>
                                <span className={s.reqArtifactValue}>
                                  {reqArtifacts.map(art => typeof art === 'string' ? art : art.name || JSON.stringify(art)).join(', ')}
                                </span>
                              </div>
                            )}
                          </div>
                        )}

                        {/* Details */}
                        <div className={s.intentDetails}>
                          <div>
                            <span className={s.intentFieldLabel}>Triggered By</span>
                            <div className={s.intentFieldValue}>{intent.triggered_by || intent.event_type || '--'}</div>
                          </div>
                          <div>
                            <span className={s.intentFieldLabel}>Created</span>
                            <div className={s.intentFieldValue}>
                              {formatTs(intent.created_at || intent.timestamp)} ({timeAgo(intent.created_at || intent.timestamp)})
                            </div>
                          </div>
                          {intent.policy_version && (
                            <div>
                              <span className={s.intentFieldLabel}>Policy Version</span>
                              <div className={s.fieldValueSecondary}>{intent.policy_version}</div>
                            </div>
                          )}
                          {intent.params && Object.keys(intent.params).length > 0 && (
                            <div>
                              <span className={s.intentFieldLabel}>Parameters</span>
                              <pre className={s.paramsPreSmall}>
                                {JSON.stringify(intent.params, null, 2)}
                              </pre>
                            </div>
                          )}
                        </div>

                        {/* Action buttons */}
                        <div className={s.actionRow}>
                          <button onClick={() => setApproveIntent(intent)} className={s.btnApproveAction}>
                            Approve
                          </button>
                          <button onClick={() => setDenyIntent(intent)} className={s.btnDeny}>
                            Deny
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {/* ── History ─────────────────────────────────────────────────── */}
          {intentSubTab === 'history' && (
            <div className={s.panel}>
              <div className={s.sectionHeader}>Intent History</div>
              {historyIntents.length === 0 ? (
                <div className={s.historyEmpty}>
                  {loading ? 'Loading history...' : 'No intent history yet'}
                </div>
              ) : (
                <div className={s.historyTableWrap}>
                  <table className={s.historyTable}>
                    <thead>
                      <tr style={{ borderBottom: `1px solid ${C.border}` }}>
                        {['Time', 'Runbook', 'Classification', 'Status', 'Resolved By', 'Policy'].map(col => (
                          <th key={col} className={s.historyTh}>{col}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {historyIntents.map((intent, i) => {
                        const classification = (intent.classification || 'AUTO').toUpperCase();
                        const classColor = classification === 'AUTO' ? C.green : C.amber;
                        const statusCol = intentStatusColor(intent.status);
                        const statusLabel = (intent.status || 'unknown').replace(/_/g, '-');
                        const approvalsList = intent.approvals_list || [];
                        const isExpanded = expandedEventId === `hist-${intent.id || i}`;

                        return (
                          <React.Fragment key={intent.id || i}>
                            <tr
                              className={s.historyTr}
                              style={{ cursor: approvalsList.length > 0 ? 'pointer' : 'default' }}
                              onClick={() => {
                                if (approvalsList.length > 0) {
                                  setExpandedEventId(isExpanded ? null : `hist-${intent.id || i}`);
                                }
                              }}
                            >
                              <td className={s.historyTdTimestamp}>
                                {formatTs(intent.resolved_at || intent.created_at || intent.timestamp)}
                              </td>
                              <td className={s.historyTdRunbook}>
                                {intent.runbook || intent.runbook_name || '--'}
                              </td>
                              <td className={s.historyTd}>
                                <span
                                  className={s.classBadge}
                                  style={{ color: classColor, background: `${classColor}15`, border: `1px solid ${classColor}25` }}
                                >
                                  {classification}
                                </span>
                              </td>
                              <td className={s.historyTd}>
                                <span className={s.statusInline} style={{ color: statusCol }}>
                                  <span className={s.statusDot} style={{ background: statusCol }} />
                                  {statusLabel}
                                </span>
                              </td>
                              <td className={s.historyTdResolvedBy}>
                                {intent.resolved_by || intent.approved_by || intent.denied_by || 'system'}
                                {approvalsList.length > 0 && (
                                  <span className={s.approvalCountBadge}>
                                    {approvalsList.length} approval{approvalsList.length > 1 ? 's' : ''}
                                  </span>
                                )}
                              </td>
                              <td className={s.historyTdPolicy}>
                                {intent.policy_version || '--'}
                              </td>
                            </tr>
                            {/* Expanded approvals detail */}
                            {isExpanded && approvalsList.length > 0 && (
                              <tr>
                                <td colSpan={6} style={{ padding: 0 }}>
                                  <div className={s.approvalExpandRow}>
                                    <div className={s.approvalExpandLabel}>Approval Details</div>
                                    <div className={s.approvalExpandList}>
                                      {approvalsList.map((ap, ai) => (
                                        <div key={ai} className={s.approvalExpandItem}>
                                          <span className={s.approvalExpandDot} />
                                          <span className={s.approvalExpandName}>
                                            {typeof ap === 'string' ? ap : ap.approved_by || ap.name || `Approver ${ai + 1}`}
                                          </span>
                                          {typeof ap === 'object' && ap.role && (
                                            <span className={s.approvalExpandRole}>{ap.role}</span>
                                          )}
                                          {typeof ap === 'object' && ap.approved_at && (
                                            <span className={s.approvalExpandTime}>{formatTs(ap.approved_at)}</span>
                                          )}
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                </td>
                              </tr>
                            )}
                          </React.Fragment>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ── Modals ──────────────────────────────────────────────────────── */}
      {approveIntent && (
        <ApprovalModal
          intent={approveIntent}
          onClose={() => setApproveIntent(null)}
          onApprove={handleApprove}
        />
      )}
      {denyIntent && (
        <DenyModal
          intent={denyIntent}
          onClose={() => setDenyIntent(null)}
          onDeny={handleDeny}
        />
      )}
    </div>
  );
}
